                    <div className="flex-1">
                      <p className="text-sm font-medium text-gray-900">
                        Status Changed to {complaint.status.replace('_', ' ')}
                      </p>
                      <p className="text-xs text-gray-500">
                        {complaint.updatedAt ? new Date(complaint.updatedAt).toLocaleDateString() : 'Recently'}
