                </h4>
                <div className="space-y-2 text-sm">
                  {complaint.blockNumber && (
                    <div className="flex justify-between">
                      <span className="text-gray-500">Block:</span>
                      <span className="font-medium text-gray-900">{complaint.blockNumber}</span>
