                      value={complaint.workerId || ""}
                      disabled={assigningWorker}
                      className="w-full px-4 py-3 rounded-xl text-sm border border-gray-300 focus:ring-2 focus:ring-primary-500 focus:border-primary-500 bg-gray-50"
                    >
                      <option value="">{complaint.workerName ? 'Change Worker' : 'Select Worker'}</option>
                      {workers.map(worker => (
                        <option key={worker.id} value={worker.id}>
                          {worker.name} ({worker.specialization || worker.department})
                        </option>
                      ))}
                    </select>
                    {complaint.workerName && (
                      <div className="p-3 bg-blue-50 text-blue-700 rounded-lg text-xs flex items-center">
                        <Zap className="h-4 w-4 mr-2" />
                        Currently assigned to {complaint.workerName}
                      </div>
                    )}
                  </div>
                </div>

                {/* False complaint / strikes — use photos & location above */}
                <div className="mb-6 border-t border-gray-200 pt-6">
                  <div className="flex items-center space-x-2 mb-4">
                    <AlertCircle className="h-5 w-5 text-amber-600" />
                    <h4 className="font-bold text-gray-900">False complaint review</h4>
                  </div>
                  <p className="text-xs text-gray-600 mb-3">
                    Review evidence and location, then record a reason. Marking false adds a strike; at three strikes the user cannot file complaints for 30 days.
                  </p>
                  {complaint.isFalseComplaint && (
                    <div className="mb-3 px-3 py-2 bg-amber-50 border border-amber-200 rounded-lg text-sm text-amber-900">
                      <strong>Flagged as false.</strong>
                      {complaint.falseComplaintReason
                        ? ` Reason: ${complaint.falseComplaintReason}`
                        : ''}
                    </div>
                  )}
                  <textarea
                    value={falseComplaintReasonInput}
                    onChange={(e) => setFalseComplaintReasonInput(e.target.value)}
                    placeholder="Reason (required to mark false)…"
                    disabled={strikeActionLoading}
                    className="w-full px-3 py-2 border border-gray-300 rounded-lg text-sm mb-3 focus:ring-2 focus:ring-primary-500"
                    rows={3}
                  />
                  <div className="flex flex-col gap-2">
                    <button
                      type="button"
                      disabled={strikeActionLoading}
                      onClick={markFalseComplaint}
                      className="w-full px-4 py-3 rounded-xl text-sm font-bold bg-amber-600 text-white hover:bg-amber-700 disabled:opacity-50"
                    >
                      Mark false complaint (+1 strike)
                    </button>
                    <button
                      type="button"
                      disabled={strikeActionLoading || !complaint.isFalseComplaint}
                      onClick={clearFalseComplaint}
                      className="w-full px-4 py-3 rounded-xl text-sm font-bold border border-gray-300 text-gray-800 hover:bg-gray-50 disabled:opacity-50"
                    >
                      Clear false flag (−1 strike)
                    </button>
                  </div>
                </div>

                {/* Quick Actions */}
                <div className="border-t border-gray-200 pt-6">
                  <h4 className="font-bold text-gray-900 mb-4">Quick Actions</h4>
                  <div className="space-y-2">
                    <Link
                      to={`/complaints/${id}/edit`}
                      className="w-full inline-flex items-center justify-center px-4 py-3 border border-gray-300 rounded-xl text-sm font-medium text-gray-700 bg-white hover:bg-gray-50 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-primary-500"
                    >
                      <Edit className="h-4 w-4 mr-2" />
                      Edit Complaint
                    </Link>
                    <button
                      onClick={() => deleteComplaint()}
                      className="w-full inline-flex items-center justify-center px-4 py-3 border border-transparent text-sm font-medium rounded-xl text-white bg-red-600 hover:bg-red-700 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-red-500"
                    >
                      <Trash2 className="h-4 w-4 mr-2" />
                      Delete Complaint
                    </button>
                  </div>
                </div>
              </div>
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

export default ComplaintDetail;
